INSERT INTO [Posts] ([Id], [UserId], [Content], [PostDate], [LikeCount]) VALUES (8, 66, 'Hic minima repellat et et et id quia cum. Qui quaerat ut esse molestiae ducimus dolore. Hic animi veritatis. Dolorem id corporis modi sint.', '2025-08-22 19:31:52', 891);
